/**
 * MedX flex layout runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Flex alignment for toolbar and form rows.
 */
const FLEX_TOKENS = Object.freeze({
  primary: { value: "layout-flex-primary", scope: "layout" },
  secondary: { value: "layout-flex-secondary", scope: "layout" },
  muted: { value: "layout-flex-muted", scope: "layout" },
  accent: { value: "layout-flex-accent", scope: "layout" },
  surface: { value: "layout-flex-surface", scope: "layout" },
});

const FLEX_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FLEX_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const flexRegistry = new Map();
const FLEX_listeners = new Set();
let FLEX_seq = 0;

function createFlexId(prefix = "medx-layout-flex") {
  FLEX_seq += 1;
  return `${prefix}-${FLEX_seq}`;
}

function registerFlex(config = {}) {
  const entryId = config.id ?? createFlexId();
  const preset = FLEX_PRESETS[config.preset ?? "default"] ?? FLEX_PRESETS.default;
  const token = FLEX_TOKENS[config.token ?? preset.token] ?? FLEX_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FLEX_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  flexRegistry.set(entryId, entry);
  notifyFlexListeners("register", entry);
  return entry;
}

function updateFlex(id, patch = {}) {
  const entry = flexRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFlexListeners("update", entry);
  return entry;
}

function resolveFlex(id) {
  const entry = flexRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFlexEntries(filter = {}) {
  let items = Array.from(flexRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFlexEvent(listener) {
  FLEX_listeners.add(listener);
  return () => FLEX_listeners.delete(listener);
}

function notifyFlexListeners(type, entry) {
  for (const listener of FLEX_listeners) {
    try {
      listener({ type, entry, registrySize: flexRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:layout:flex] listener error", err.message);
    }
  }
}

function getFlexMetrics() {
  const items = listFlexEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FLEX_TOKENS).length,
    presets: Object.keys(FLEX_PRESETS).length,
  };
}

async function runMedxFlex() {
  console.log("[medx:ui:layout:flex] runtime initialized");
  console.log(`[medx:ui:layout:flex] tokens=${Object.keys(FLEX_TOKENS).length} presets=${Object.keys(FLEX_PRESETS).length}`);

  const events = [];
  onFlexEvent((e) => events.push(e.type));

  const domains = Object.keys(FLEX_SUPPLY_CHAIN);
  const presets = Object.keys(FLEX_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerFlex({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "layout/flex" },
    });
  }

  const first = listFlexEntries()[0];
  if (first) updateFlex(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFlexMetrics();
  const resolved = first ? resolveFlex(first.id) : null;

  console.log(`[medx:ui:layout:flex] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:layout:flex] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:layout:flex] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:layout:flex] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:layout:flex] bootstrap complete");
}

module.exports = runMedxFlex;
